function synchronizeAnnouncements() {
  // Clear existing slides but keep the header
  const header = document.querySelector('#slideshowContainer .announcementLabel');
  while (slideshowContainer.lastChild !== header) {
    slideshowContainer.removeChild(slideshowContainer.lastChild);
  }

  const gridItems = document.querySelectorAll("#announcementGrid .gridItem");

  gridItems.forEach(item => {
    const iconElement = item.querySelector('i');
    const textElement = item.querySelector('h6');

    if (iconElement && textElement) {
      const slide = document.createElement('div');
      slide.className = 'slide';

      const slideContent = document.createElement('div');
      slideContent.className = 'slideContent';

      const icon = iconElement.cloneNode(true);
      const text = textElement.cloneNode(true);

      slideContent.appendChild(icon);
      slideContent.appendChild(text);
      slide.appendChild(slideContent);

      slideshowContainer.appendChild(slide);
    }
  });

  slides = Array.from(slideshowContainer.querySelectorAll('.slide'));
  if (slides.length > 0) {
    slides[0].classList.add('active');
  }
  currentSlideIndex = 0;
}
